#include<bits/stdc++.h>
using namespace std;
int main(void){int cmd,x,n;queue<int>q;
    cin>>n;
    for(int i=1;i<=n;i++){cin>>cmd;
    	switch(cmd){
    		case(1):cin>>x,q.push(x);break;
			case(2):{
				if(q.empty()){cout<<"ERR_CANNOT_POP"<<endl;}
            	else{q.pop();}
				break;
			}
			case(3):{
				if(q.empty()){cout<<"ERR_CANNOT_QUERY"<<endl;}
            	else{cout<<q.front()<<endl;}
				break;
			}
			case(4):cout<<q.size()<<endl;break;
		}
    }
    return false;
}
